// bitwise
const FLAG_READ = 0b0001;
const FLAG_WRITE = 0b0010;
const perms = FLAG_READ | FLAG_WRITE;
console.log((perms & FLAG_READ) !== 0);

int FLAG_READ = 0b0001;
int FLAG_WRITE = 0b0010;
int perms = FLAG_READ | FLAG_WRITE;
boolean result = (perms & FLAG_READ) != 0;
System.out.println(result);

DECLARE @FLAG_READ INT = 1;
DECLARE @FLAG_WRITE INT = 2;
DECLARE @perms INT = @FLAG_READ | @FLAG_WRITE;
SELECT CASE WHEN (@perms & @FLAG_READ) <> 0 THEN 1 ELSE 0 END AS result;
